use std::collections::HashMap;

struct ProcessRecord {
    pid: u32,
    name: String,
    start_time: std::time::Instant,
}

impl std::fmt::Display for ProcessRecord {
    fn fmt(&self, f: &mut std::fmt::Formatter) -> std::fmt::Result {
        write!(f, "PID: {}, Name: {}", self.pid, self.name)
    }
}

struct SystemState {
    processes: HashMap<u32, ProcessRecord>,
}

impl SystemState {
    fn new() -> Self {
        SystemState { processes: HashMap::new() }
    }

    fn add_process(&mut self, pid: u32, name: &str) {
        let record = ProcessRecord {
            pid, 
            name: name.to_string(),
            start_time: std::time::Instant::now(),
        };
        self.processes.insert(pid, record);
    }

    fn list_active(&self) -> Vec<String> {
        let mut list = Vec::new();
        for (pid, record) in &self.processes { 
            list.push(format!("{}", record));
        }
        list
    }
}

fn main() {
    let mut state = SystemState::new();
    state.add_process(100, "init");
    state.add_process(250, "shell");
    state.add_process(999, "debugger");

    println!("System Initialized.");
    for item in state.list_active() {
        println!("-> {}", item);
    }
}

use std::collections::HashMap;
use std::fs::File;
use std::io::Read;

struct AppSettings {
    version: String,
    max_connections: u32,
}

impl AppSettings {
    fn new(settings: HashMap<String, String>) -> Self {
        let mut version = "Unknown".to_string();
        let mut max_connections = 0;

        if let Some(v) = settings.get("version") {
            version = v.clone();
        }
        if let Some(c_str) = settings.get("max_connections") {
            match c_str.parse::<u32>() {
                Ok(val) => max_connections = val,
                Err(_) => {}
            }
        }

        AppSettings {
            version,
            max_connections,
        }
    }
}

fn load_settings_from_file(filepath: &str) -> Result<AppSettings, std::io::Error> {
    let mut file = File::open(filepath)?;
    let mut contents = String::new();
    file.read_to_string(&mut contents)?;

    let mut settings_map = HashMap::new();
    for line in contents.lines() {
        let trimmed = line.trim();
        if !trimmed.is_empty() && !trimmed.starts_with("#") {
            let parts: Vec<&str> = trimmed.split(":").collect();
            if parts.len() == 2 {
                settings_map.insert(parts[0].trim().to_string(), parts[1].trim().to_string());
            }
        }
    }

    Ok(AppSettings::new(settings_map))
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    use std::env;

    let args: Vec<String> = env::args().collect();
    if args.len() != 2 {
        eprintln!("Usage: {}, <config_file_path>", env::args().next().unwrap());
        return Ok(());
    }

    let config_path = &args[1];
    match load_settings_from_file(config_path) {
        Ok(settings) => {
            println!("Successfully loaded application settings.");
            println!("Version: {}", settings.version);
            println!("Max Connections: {}", settings.max_connections);
        }
        Err(e) => {
            eprintln!("Failed to load settings: {}", e);
        }
    }

    Ok(())
}

