use std::fs::File;
use std::io::{self, BufRead, BufReader};

struct DeviceConfig {
    user_id: u32,
    device_name: String,
}

fn process_config_pipeline(input_filepath: &str) -> io::Result<Vec<DeviceConfig>> {
    let file = File::open(input_filepath)?;
    let reader = BufReader::new(file);

    let mut found_configs = Vec::new();

    for line in reader.lines() {
        let line = line?;
        if line.starts_with("#METADATA:") {
            let parts: Vec<&str> = line.split(':').collect();
            if parts.len() == 2 {
                let metadata = parts[1].trim();
                if metadata.contains("user=1001") {
                    found_configs.push(DeviceConfig { user_id: 1001, device_name: String::from("Keyboard") });
                }
            }
        } else if line.contains("device=Mouse") && line.contains("user=1001") {
            let parts: Vec<&str> = line.split(',').collect();
            if let Some(device_info) = parts.iter().find(|&&s| s.contains("device=")) {
                let name = device_info.split('=').nth(1).unwrap_or("").trim().to_string();
                found_configs.push(DeviceConfig { user_id: 1001, device_name: name });
            }
        }
    }
    Ok(found_configs)
}

fn main() -> io::Result<()> {
    let config_path = "/tmp/device_manifest.txt";
    std::fs::write(config_path, "#METADATA: type=input user=1001nuser_data, device=Mouse, user=1001nother_junk linen#METADATA: type=output user=2000n")?;

    match process_config_pipeline(config_path) {
        Ok(configs) => {
            println!("Successfully processed {} device configurations.", configs.len());
            for config in configs {
                println!("Found: User ID {}, Device {}", config.user_id, config.device_name);
            }
        },
        Err(e) => {
            eprintln!("Error processing pipeline: {}", e);
        }
    }
    Ok(())
}
